def interval_intersection(intervals1, intervals2):
    if not intervals1 or not intervals2:
        return []

    i1, i2 = 0, 0
    result = []

    while i1 < len(intervals1) and i2 < len(intervals2):
        start = max(intervals1[i1][0], intervals2[i2][0])
        end = min(intervals1[i1][1], intervals2[i2][1])

        if start <= end:
            result.append([start, end])

        if intervals1[i1][1] < intervals2[i2][1]:
            i1 += 1
        else:
            i2 += 1

    return result

def edit_distance(a, b):
    m, n = len(a), len(b)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(m + 1):
        for j in range(n + 1):
            if i == 0:
                dp[i][j] = j
            elif j == 0:
                dp[i][j] = i
            elif a[i - 1] == b[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = 1 + min(dp[i][j - 1],      # Insert
                                   dp[i - 1][j],      # Remove
                                   dp[i - 1][j - 1])  # Replace
    return dp[m][n]

def lis_length(nums):
    if not nums:
        return 0
    dp = [1] * len(nums)
    for i in range(1, len(nums)):
        for j in range(i):
            if nums[i] > nums[j]:
                dp[i] = max(dp[i], dp[j] + 1)
    return max(dp)
